UPDATE ai_knowledge
SET parent_id = #{parentId}, name = #{name}, content = #{content}, doc_type = #{docType}, source_type = #{sourceType},
status = #{status},
update_time = #{updateTime}, update_user = #{updateUser}
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM ai_knowledge
WHERE project_id = #{projectId}
  AND parent_id = #{parentId}
  AND status != 'deleted'
